             * This treats the input as a literal value rather than executable code.
             */
            xpath.setXPathVariableResolver(variableName -> {
                if ("username".equals(variableName.getLocalPart())) {
                    return username;
                }
                return null;
            });

            /**
             * 5. Construct and evaluate the XPath expression.
             * The expression finds the 'role' child node of a 'user' node where the 'name' child matches our variable.
             * XPathConstants.STRING returns the text content of the node or an empty string if not found.
             */
            String expression = "/users/user[name=$username]/role";
            String role = (String) xpath.evaluate(expression, doc, XPathConstants.STRING);

            // Return the role if found, or null if the user does not exist (result is empty)
            return (role == null || role.isEmpty()) ? null : role;

        } catch (Exception e) {
            // Log the exception in a real-world application
            // Returning null as per requirements for non-existent users or processing errors
            return null;
        }
    }
